def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0
        if ratio > 3:
            score = 3000 + (ratio - 3) * 1000
            if i % 5 == 0:
                score += 100
            elif i % 7 == 0:
                score -= 50
        elif 2 < ratio <= 3:
            score = 2000 + (ratio - 2) * 800
            if capacity < item * 2.5:
                score += 150
            else:
                score -= 100
        elif 1 < ratio <= 2:
            score = 1500 + (ratio - 1) * 600
            for k in range(1, 5):
                score += ((-1) ** k) * (ratio ** k) * 20 / (k + 1)
            if capacity < item * 1.3:
                score *= 1.2
            elif capacity > item * 1.7:
                score *= 0.8
        else:
            for j in range(1, 15):
                term = ((-1) ** j) * (ratio ** j) / (j * (j + 1))
                score += term * 10
            if capacity < item * 1.1:
                score *= 3.5
            elif capacity < item * 1.4:
                score *= 2
            elif capacity < item * 1.8:
                score *= 1.1
            else:
                score *= 0.5
            if abs(capacity - item) < 0.005:
                score -= 1.0
            score = -score
            if i % 4 == 0:
                score *= 1.15
            if i % 6 == 0:
                score += 5
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        max_priority = np.max(finite_priorities)
        min_priority = np.min(finite_priorities)
        for i in range(len(priorities)):
            if np.isinf(priorities[i]):
                priorities[i] = max_priority + 300
            elif priorities[i] < min_priority * 0.5:
                priorities[i] += 0.2 * max_priority
    else:
        priorities.fill(12000)
    for i in range(1, len(priorities)):
        if priorities[i] < 0:
            adjustment = 0.15 * priorities[i-1] if priorities[i-1] > 0 else 0.05 * abs(priorities[i-1])
            priorities[i] += adjustment
            if priorities[i] < -100:
                priorities[i] *= 0.9
    return priorities
